    if (_nextButton == nil) {
        _nextButton = [UIButton buttonWithType:UIButtonTypeCustom];
        [_nextButton setTitle:@"Switch" forState:UIControlStateNormal];
        [_nextButton setTitleColor:WHITE_COLOR forState:UIControlStateNormal];
        _nextButton.titleLabel.font = [UIFont systemFontOfSize:16 weight:UIFontWeightBold];

