- (NSString *)getRandomElementFromArray:(NSArray *)array {
    if (array.count == 0) {
        return nil; // 数组为空时返回 nil
    }
    // 生成随机索引（0 到 array.count-1）
    NSUInteger randomIndex = arc4random_uniform((uint32_t)array.count);
    return array[randomIndex];
}

