- (UIButton *)createButtonWithTitle:(NSString *)title
                          imageName:(NSString *)imageName
                             action:(SEL)action {
    UIButton *button = [[UIButton alloc] init];

    button.backgroundColor = CLEAR_COLOR;


    UIImageView *iconImageView = [[UIImageView alloc] initWithImage:[UIImage imageNamed:imageName]];
    iconImageView.contentMode = UIViewContentModeScaleAspectFit;
    [button addSubview:iconImageView];
    [iconImageView mas_makeConstraints:^(MASConstraintMaker *make) {
        make.centerY.equalTo(button);
        make.left.equalTo(button);
        make.width.height.mas_equalTo(ZOOM(24));
    }];

    UILabel *titleLabel = [[UILabel alloc] init];
    titleLabel.font = KEEPASS_FONT(14);
    titleLabel.textColor = DEEP_COLOR_1;
    titleLabel.text=title;
    titleLabel.textAlignment=NSTextAlignmentLeft;
    [button addSubview:titleLabel];
    [titleLabel mas_makeConstraints:^(MASConstraintMaker *make) {
        make.centerY.equalTo(button);
        make.left.equalTo(iconImageView.mas_right).offset(ZOOMW(4));
        make.height.mas_equalTo(ZOOM(22));
    }];

    // 添加点击事件
    [button addTarget:self action:action forControlEvents:UIControlEventTouchUpInside];

    return button;
