- (void)gotoAdd {
    PlateEditViewController *addNewVC = [[PlateEditViewController alloc] initForCreation:YES];
    addNewVC.headerView.titleLabel.text = NSLocalizedString(@"New Target", nil); // 使用本地化字符串
    addNewVC.modalPresentationStyle = UIModalPresentationOverFullScreen;
    [self presentViewController:addNewVC animated:YES completion:^{
        [SVProgressHUD dismiss];
    }];
}

- (void)modifyButtonTapped:(UIButton *)sender {
    [sender showClickedAnimationWithLevel:2];

    PlateRotatingModel *plateRotatingModel = [PlateRotatingModel sharedInstance];
    if (plateRotatingModel.options.count == 0) {
        UIAlertController *alertController = [UIAlertController alertControllerWithTitle:NSLocalizedString(@"Tips", nil)
                                                                                 message:NSLocalizedString(@"Please create an new target！", nil)
                                                                          preferredStyle:UIAlertControllerStyleAlert];
        UIAlertAction *okAction = [UIAlertAction actionWithTitle:NSLocalizedString(@"Confirm", nil)
                                                           style:UIAlertActionStyleDefault
                                                         handler:nil];
        [alertController addAction:okAction];
        [self presentViewController:alertController animated:YES completion:nil];
    } else {
        PlateEditViewController *editVC = [[PlateEditViewController alloc] initForCreation:NO];
        editVC.headerView.titleLabel.text = NSLocalizedString(@"Edit", nil); // 使用本地化字符串
        editVC.modalPresentationStyle = UIModalPresentationOverFullScreen;
        [self presentViewController:editVC animated:YES completion:^{
            self.editButton.hidden = YES;
            [SVProgressHUD dismiss];
        }];
    }
}

- (void)startButtonTapped:(UIButton *)sender{
    [sender showClickedAnimationWithLevel:2];

    [_startButton setTitle:@"Refresh" forState:UIControlStateNormal];

    PlateRotatingModel *plateRotatingModel = [PlateRotatingModel sharedInstance];

    NSString *randomElement = [self getRandomElementFromArray:plateRotatingModel.options];

    self.resLabel.text = randomElement;

    _resetButton.hidden = NO;

}

- (NSString *)getRandomElementFromArray:(NSArray *)array {
    if (array.count == 0) {
        return nil; // 数组为空时返回 nil
    }
    // 生成随机索引（0 到 array.count-1）
    NSUInteger randomIndex = arc4random_uniform((uint32_t)array.count);
    return array[randomIndex];
}

- (void)startAutoRotation {
    [self.optionsWheelView startAutoRotation];
}

