- (void)addOptionButtonTapped:(UIButton *)sender {
    [sender showClickedAnimationWithLevel:2];

    if (self.optionsArray.count >= 8) {
        [SVProgressHUD showErrorWithStatus:NSLocalizedString(@"Maximum 8 options allowed", nil)];
        return;
    }

    UIAlertController *alertController = [UIAlertController alertControllerWithTitle:NSLocalizedString(@"Add Option", nil) message:NSLocalizedString(@"Please enter a new option:", nil) preferredStyle:UIAlertControllerStyleAlert];
    [alertController addTextFieldWithConfigurationHandler:^(UITextField * _Nonnull textField) {
        textField.placeholder = NSLocalizedString(@"Enter option", nil);
        textField.keyboardType = UIKeyboardTypeDefault;
    }];

    UIAlertAction *cancelAction = [UIAlertAction actionWithTitle:NSLocalizedString(@"Cancel", nil) style:UIAlertActionStyleCancel handler:nil];
    UIAlertAction *confirmAction = [UIAlertAction actionWithTitle:NSLocalizedString(@"OK", nil) style:UIAlertActionStyleDefault handler:^(UIAlertAction * _Nonnull action) {
        [self handleAddOption:alertController.textFields.firstObject.text];
    }];

    [alertController addAction:cancelAction];
    [alertController addAction:confirmAction];
    [self presentViewController:alertController animated:YES completion:nil];
    }

    - (void)handleAddOption:(NSString *)text {
        if (text.length == 0) {
            [self showWarningAlertWithMessage:NSLocalizedString(@"No new option entered!", nil)];
            return;
        }
        if (text.length > 9) {
            [self showWarningAlertWithMessage:NSLocalizedString(@"Option cannot exceed 8 characters!", nil)];
            return;
        }

        [self.optionsArray addObject:text];
        [self.editCollectionView reloadData];
        self.tipLabel.hidden = YES;
    }

