@property (nonatomic, assign) int minutes;
@property (nonatomic, assign) int milliseconds;

@end


@implementation TimeView

- (instancetype)init {
    self = [super init];
    if (self) {
        self.seconds = 0;
        self.minutes = 0;
        self.milliseconds = 0;
        [self setUpUI];
    }
    return self;
}


#pragma mark - setUpUI

- (void)setUpUI {
    self.backgroundColor = [UIColor clearColor];

    [self addAllSubviews];
    [self addAllConstraints];

}

- (void)addAllSubviews {
    [self addSubview:self.imageView];
    [self addSubview:self.timeLabel];
    [self addSubview:self.mmTimeLabel];
}

- (void)addAllConstraints {
    [_imageView mas_makeConstraints:^(MASConstraintMaker *make) {
        make.right.equalTo(self.timeLabel.mas_left).offset(ZOOM(-10));
        make.centerY.equalTo(self);
        make.width.mas_equalTo(ZOOM(32));
        make.height.mas_equalTo(ZOOM(32));
    }];

    [_timeLabel mas_makeConstraints:^(MASConstraintMaker *make) {
        make.centerY.centerX.equalTo(self);
        make.width.mas_equalTo(ZOOM(150));
        make.height.mas_equalTo(ZOOM(62));
    }];

    [_mmTimeLabel mas_makeConstraints:^(MASConstraintMaker *make) {
        make.left.equalTo(self.timeLabel.mas_right).offset(ZOOM(0));
        make.centerY.equalTo(self);
        make.width.mas_equalTo(ZOOM(30));
        make.height.mas_equalTo(ZOOM(17));
    }];
}

#pragma mark - 计时相关的方法

- (void)startTiming {
    if (!_timer) {
        _timer = [NSTimer scheduledTimerWithTimeInterval:0.01 target:self selector:@selector(updateTime) userInfo:nil repeats:YES];
    }
}

- (void)pauseTiming {
    if (_timer) {
        [_timer invalidate];
        _timer = nil;
    }
}

- (void)resetTiming {
    if (_timer) {
        [_timer invalidate];
        _timer = nil;
    }
    self.seconds = 0;
    self.minutes = 0;
    self.milliseconds = 0;
    self.timeLabel.text = @"00:00";
    self.mmTimeLabel.text = @"000";
}

- (void)updateTime {

    self.milliseconds++;
    if (self.milliseconds >= 100) {
        self.seconds++;
        self.milliseconds = 0;
    }
    if (self.seconds >= 60) {
        self.minutes++;
        self.seconds = 0;
    }

    NSString *secondString = [NSString stringWithFormat:@"%02d", self.seconds];
    NSString *minuteString = [NSString stringWithFormat:@"%02d", self.minutes];
    NSString *millisecondString = [NSString stringWithFormat:@"%03d", self.milliseconds];

    self.timeLabel.text = [minuteString stringByAppendingString:[@":" stringByAppendingString:secondString]];
    self.mmTimeLabel.text = millisecondString;
}



