- (void)increaseScore:(UIButton *)sender {
    [sender showClickedAnimationWithLevel:2];
    if (self.score < 99) {
        self.score++;
        self.scoreLabel.text = [NSString stringWithFormat:@"%02d", self.score]; // 格式化显示两位数
    } else {
        [SVProgressHUD showWithStatus:@"Top Score!"];
        [SVProgressHUD dismissWithDelay:1];   // 1秒后关闭提示框
    }
}

- (void)decreaseScore:(UIButton *)sender {
    [sender showClickedAnimationWithLevel:2];
    if (self.score > 0) {
        self.score--;
        self.scoreLabel.text = [NSString stringWithFormat:@"%02d", self.score]; // 格式化显示两位数
    } else {
        // 不能减为负数，0时不处理减数操作
    }
}


